func colorOrDefault(color string) string {
	if color == "" {
		return "#6366f1"
	}
	return color
}

func transitPointVal(tp *domain.TransitPoint, field string) string {
	if tp == nil {
		return ""
	}
	switch field {
	case "location":
		return tp.Location
	case "code":
		return tp.Code
	case "latitude":
		return tp.Latitude
	case "longitude":
		return tp.Longitude
	}
	return ""
}

func accommodationVal(a *domain.Accommodation, field string) string {
	if a == nil {
		return ""
	}
	switch field {
	case "name":
		return a.Name
	case "neighborhood":
		return a.Neighborhood
	case "address":
		return a.Address
	case "checkin":
		return a.CheckIn
	case "checkout":
		return a.CheckOut
	case "ref":
		return a.BookingReference
	}
	return ""
}

