// editEventTypeDisplay returns "display:none" if the event type doesn't match the section type,
// or "" (visible) if it does.
func editEventTypeDisplay(eventType, sectionType string) string {
	if eventType == sectionType {
		return ""
	}
	return "display:none"
}

